import{_ as t,o,c as a,a2 as s}from"./chunks/framework.C69UpXSI.js";const p=JSON.parse('{"title":"Economy Mode","description":"","frontmatter":{},"headers":[],"relativePath":"en/configuration/economy.md","filePath":"en/configuration/economy.md"}'),n={name:"en/configuration/economy.md"};function i(r,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="economy-mode" tabindex="-1">Economy Mode <a class="header-anchor" href="#economy-mode" aria-label="Permalink to &quot;Economy Mode&quot;">​</a></h1><p>TurboDev&#39;s <strong>Economy Mode</strong> reduces token consumption by instructing the AI to produce concise output. When active, the system prompt includes a directive that makes the LLM drop filler words, use sentence fragments, and keep code exact — same technical accuracy, ~50-70% fewer output tokens, direct cost savings.</p><p>Inspired by <a href="https://github.com/JuliusBrussee/caveman" target="_blank" rel="noreferrer">Caveman</a>, implemented natively — no external skill or dependency.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>You activate a level with <code>/economy eco</code> or <code>/economy ultra</code></li><li>TurboDev adds a conciseness directive to the system prompt</li><li>The LLM produces shorter responses — fragments instead of paragraphs</li><li>Code, commands, file paths, and error messages stay <strong>byte-exact</strong></li><li>The level is persisted in <code>~/.turbodevrc</code> and survives restarts</li></ol><p>The economy directive costs ~60 tokens (negligible compared to the output savings).</p><h2 id="levels" tabindex="-1">Levels <a class="header-anchor" href="#levels" aria-label="Permalink to &quot;Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Estimated Output Savings</th><th>Badge</th></tr></thead><tbody><tr><td><code>off</code> (default)</td><td>Normal output — full sentences, explanations</td><td>0%</td><td>—</td></tr><tr><td><code>eco</code></td><td>Direct and concise. No filler, no pleasantries.</td><td>~50%</td><td><code>ECO</code> (yellow)</td></tr><tr><td><code>ultra</code></td><td>Telegraphic fragments. No explanations unless asked.</td><td>~70%</td><td><code>ULTRA</code> (red)</td></tr></tbody></table><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/economy</code></td><td>Show current level and usage</td></tr><tr><td><code>/economy eco</code></td><td>Activate eco level (alias: <code>/economy on</code>)</td></tr><tr><td><code>/economy ultra</code></td><td>Activate ultra level</td></tr><tr><td><code>/economy off</code></td><td>Deactivate economy mode</td></tr></tbody></table><h2 id="before-after" tabindex="-1">Before / After <a class="header-anchor" href="#before-after" aria-label="Permalink to &quot;Before / After&quot;">​</a></h2><h3 id="normal-69-tokens" tabindex="-1">Normal (69 tokens) <a class="header-anchor" href="#normal-69-tokens" aria-label="Permalink to &quot;Normal (69 tokens)&quot;">​</a></h3><blockquote><p>&quot;The reason your React component is re-rendering is likely because you&#39;re creating a new object reference on each render cycle. I&#39;d recommend using useMemo to memoize the object.&quot;</p></blockquote><h3 id="eco-35-tokens" tabindex="-1">Eco (~35 tokens) <a class="header-anchor" href="#eco-35-tokens" aria-label="Permalink to &quot;Eco (~35 tokens)&quot;">​</a></h3><blockquote><p>&quot;Component re-renders because inline object prop creates new ref each cycle. Wrap in <code>useMemo</code>.&quot;</p></blockquote><h3 id="ultra-19-tokens" tabindex="-1">Ultra (~19 tokens) <a class="header-anchor" href="#ultra-19-tokens" aria-label="Permalink to &quot;Ultra (~19 tokens)&quot;">​</a></h3><blockquote><p>&quot;Inline object prop = new ref each render = re-render. Use <code>useMemo</code>.&quot;</p></blockquote><p>Same fix. Same accuracy. Fewer tokens.</p><h2 id="what-stays-exact" tabindex="-1">What Stays Exact <a class="header-anchor" href="#what-stays-exact" aria-label="Permalink to &quot;What Stays Exact&quot;">​</a></h2><p>Economy mode compresses <strong>prose style</strong>, not <strong>technical content</strong>:</p><ul><li>✅ Code blocks — byte-exact</li><li>✅ Commands and CLI flags — exact</li><li>✅ File paths — exact</li><li>✅ Error messages — exact</li><li>✅ User&#39;s language — preserved (Italian input → concise Italian output)</li><li>❌ Filler words (&quot;let me...&quot;, &quot;sure!&quot;, &quot;I&#39;ll now...&quot;) — dropped</li><li>❌ Restating the question — dropped</li><li>❌ Transitions and pleasantries — dropped</li></ul><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>The level is saved in <code>~/.turbodevrc</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;economy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;eco&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>On startup, TurboDev loads the saved level and activates economy mode automatically. Toggle it anytime with <code>/economy</code>.</p><h2 id="statusbar" tabindex="-1">StatusBar <a class="header-anchor" href="#statusbar" aria-label="Permalink to &quot;StatusBar&quot;">​</a></h2><p>When economy mode is active, the StatusBar shows a colored badge:</p><ul><li><code>ECO</code> (yellow) — eco level active</li><li><code>ULTRA</code> (red) — ultra level active</li></ul><p>The badge sits next to the cost indicator so you can see both savings and spending at a glance.</p><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><ul><li><strong><code>eco</code></strong> — daily work. Direct responses, still readable. Best balance of clarity and savings.</li><li><strong><code>ultra</code></strong> — power sessions. Maximum density, minimal prose. You know what you&#39;re doing and just want the answer.</li><li><strong><code>off</code></strong> — learning/exploring. When you want full explanations and context.</li></ul><h2 id="inspiration" tabindex="-1">Inspiration <a class="header-anchor" href="#inspiration" aria-label="Permalink to &quot;Inspiration&quot;">​</a></h2><p>Economy Mode is inspired by <a href="https://github.com/JuliusBrussee/caveman" target="_blank" rel="noreferrer">Caveman</a> by Julius Brussee — a Claude Code skill that proved a simple prompt instruction can cut 65% of output tokens without losing technical accuracy. TurboDev implements its own native conciseness prompt; it does not bundle or install the Caveman skill.</p>`,33)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
